package com.stockmind.bootstrap;
import com.stockmind.bootstrap.business.tool.FactorAnalysisTools;import com.stockmind.bootstrap.business.tool.ScenarioValuationTools;
import com.fasterxml.jackson.databind.*;import com.stockmind.application.factor.*;import com.stockmind.application.instrument.*;import com.stockmind.application.market.*;import com.stockmind.application.research.AnalystReport;import com.stockmind.application.sector.*;import com.stockmind.application.snapshot.*;import com.stockmind.domain.market.*;import java.math.*;import java.time.*;import java.util.*;
public final class FactorAnalysisToolsAcceptanceTest{public static void main(String[]a)throws Exception{MarketDataProvider market=new MarketDataProvider(){public com.stockmind.domain.market.MarketQuote loadQuote(String s){throw new AssertionError("历史画像不应读取实时行情");}public BarDataset loadBars(HistoricalBarsQuery q){List<MarketBar>b=new ArrayList<>();LocalDate start=q.endDate().minusDays(300);for(int i=0;i<260;i++){Instant t=start.plusDays(i).atTime(15,0).atZone(ZoneId.of("Asia/Shanghai")).toInstant();BigDecimal p=BigDecimal.valueOf(100+i*.01);b.add(new MarketBar(q.instrumentId(),BarInterval.DAY_1,t.minusSeconds(19800),t,p,p,p,p,BigDecimal.valueOf(1000),BigDecimal.valueOf(100000),q.adjustment()));}return new BarDataset("bars",b,"fixture",Instant.parse("2026-07-17T08:00:00Z"),List.of());}};SectorDataProvider sector=new SectorDataProvider(){public List<SectorSnapshot>loadIndustrySectors(String s){throw new AssertionError();}public SectorConstituentSet loadTopIndustryConstituents(String s,int l){throw new AssertionError("历史画像不应读取当前同行");}};var snapshots=new PointInTimeStockSnapshotService(new InstrumentResolver(),market,(s,t,p)->List.of(),(s,l)->reports(),(s,l)->List.of(),sector);var profileService=new StockFactorProfileService(snapshots,List.of(new ValuationFactorCalculator(),new QualityFactorCalculator(),new GrowthFactorCalculator(),new ExpectationRevisionFactorCalculator(),new MomentumRiskFactorCalculator(),new ShareholderReturnFactorCalculator()));ObjectMapper mapper=new ObjectMapper();var tools=new FactorAnalysisTools(profileService,new com.stockmind.application.analysis.StockInvestmentAnalysisService());JsonNode compact=mapper.readTree(tools.stockFactorProfile(Map.of("symbol","SH600519","as_of","2026-07-17","style","BALANCED"),""));require("COMPACT".equals(compact.path("data").path("detail_level").asText())&&!compact.path("data").has("categories"),"默认画像必须使用不含完整分类数组的COMPACT输出");require(compact.path("data").path("key_metrics").isObject()&&compact.path("data").path("investment_analysis").isObject(),"COMPACT画像必须保留关键指标和业务分析结果");require(compact.path("data").path("analysis_signals").isArray()&&compact.path("data").path("investment_theses").isArray()&&!compact.path("data").path("investment_stance").asText().isBlank(),"上下文压缩前必须在顶层提供投资立场、信号和论点");String json=tools.stockFactorProfile(Map.of("symbol","SH600519","as_of","2026-07-17","style","BALANCED","detail_level","FULL"),"");JsonNode root=mapper.readTree(json);require("success".equals(root.path("status").asText()),"stock_factor_profile调用失败: "+json);require(root.path("data").path("categories").size()==6,"工具未返回六类因子");require(root.path("data").path("key_metrics").has("pe_ttm_percentile_3y"),"画像未提升三年PE分位到关键指标");JsonNode analysis=root.path("data").path("investment_analysis");require(analysis.path("signals").isArray()&&analysis.path("theses").size()==7,"业务分析中间层必须返回信号和七类投资论点");require(!analysis.path("stance").asText().isBlank()&&!analysis.path("judgment").asText().isBlank(),"业务分析中间层必须形成明确投资立场");require(!root.path("data").has("prohibited_claims")&&!root.path("data").has("claim_permissions")&&!root.path("data").has("follow_up_policy"),"工具输出不应继续向模型暴露禁止句式和指定性跟进策略");require("0-100".equals(root.path("data").path("score_scale").asText()),"综合评分必须说明分值范围");require("stock-factor-v1".equals(root.path("data").path("policy_version").asText()),"策略版本缺失");String scenarioJson=new ScenarioValuationTools(new ScenarioValuationService(snapshots)).analyze(Map.of("symbol","SH600519","as_of","2026-07-17"),"");JsonNode scenario=mapper.readTree(scenarioJson);require("success".equals(scenario.path("status").asText()),"scenario_valuation_analysis调用失败");require(!scenario.path("data").path("unique_range_available").asBoolean()&&scenario.path("data").path("sensitivity_matrix").size()==9,"未提供Forward PE假设时应只返回敏感性矩阵");require("TRAILING_TWELVE_MONTHS".equals(scenario.path("data").path("market_pe_basis").asText())&&!scenario.path("data").path("ttm_pe_comparable_to_target_pe").asBoolean(),"TTM PE与Forward PE口径未显式分离");require("NEXT_FISCAL_YEAR_INSTITUTION_CONSENSUS_MEDIAN".equals(scenario.path("data").path("scenario_eps_basis").asText()),"情景EPS年度口径缺失");}private static List<AnalystReport>reports(){List<AnalystReport>r=new ArrayList<>();for(int i=0;i<3;i++)r.add(new AnalystReport("r"+i,"600519","研报","机构"+i,LocalDate.of(2026,7,1),"买入",BigDecimal.TEN,BigDecimal.valueOf(11),BigDecimal.valueOf(12),""));return r;}private static void require(boolean c,String m){if(!c)throw new AssertionError(m);}}
